import{_ as a,o as e,c as p,ae as i}from"./chunks/framework.BzQXgbNp.js";const u=JSON.parse('{"title":"使用 CocoaPods 做依赖管理","description":"","frontmatter":{"title":"使用 CocoaPods 做依赖管理","date":"2015-02-11 15:10:58 +0800","draft":false},"headers":[],"relativePath":"posts/cocoapods.md","filePath":"posts/cocoapods.md","lastUpdated":1783569911000}'),o={name:"posts/cocoapods.md"};function t(l,s,n,d,c,h){return e(),p("div",null,[...s[0]||(s[0]=[i(`<p><a href="http://www.cocoapods.org" target="_blank" rel="noreferrer">CocoaPods</a> 可以为 iOS 项目使用的第三方类库和我们自己的私有类库提供依赖管理，我们只需要告诉它要使用的类库名称和版本号，然后再执行一条命令，它就会自动将这个类库的源码下载到本地，并且为工程设置好相应的系统依赖和编译项。</p><h1 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h1><p>由于 CocoaPods 是用 ruby 写的，所以需要有 ruby 环境和 git 环境，尽量使用 rvm 来管理 ruby，可避免因权限导致的 gem install 失败问题。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo gem update –system</span></span></code></pre></div><p>为了提高下载速度，还需要将 ruby 源更改为国内地址</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gem sources -a https://gems.ruby-china.com/ -r https://rubygems.org/</span></span>
<span class="line"><span>gem sources -l</span></span></code></pre></div><h1 id="安装并使用-cocoapods" tabindex="-1">安装并使用 CocoaPods <a class="header-anchor" href="#安装并使用-cocoapods" aria-label="Permalink to &quot;安装并使用 CocoaPods&quot;">​</a></h1><p>安装 CocoaPods</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo gem install cocoapods (更新也用这个)</span></span></code></pre></div><p>下载 CocoaPods 维护的所有 podspec 文件到&quot;~/.cocoapods/repos/master/Specs&quot;，podspec 文件主要用来描述依赖库的名称、版本、作者、下载地址等信息。通过 CocoaPods 下载第三方类库，其实就是根据我们指定的类库名称找到相关的 podspec，然后再根据 podspec 文件中指定的地址去下载。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod setup</span></span></code></pre></div><p>查看 CocoaPods 管理的依赖库信息</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod search 依赖库的名字</span></span></code></pre></div><p>新建 Podfile 文件，此文件用于配置项目所需要使用的依赖库</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd &quot;项目根目录&quot;</span></span>
<span class="line"><span>pod init</span></span></code></pre></div><p>打开 Podfile 文件，按下面内容配置依赖关系，Podfile 的更详细配置方法可参照<a href="http://guides.cocoapods.org/syntax/podfile.html" target="_blank" rel="noreferrer">官方文档</a></p><div class="language-ruby vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">source </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;https://github.com/CocoaPods/Specs.git&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">platform </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:ios</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;7.0&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inhibit_all_warnings!</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">target </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;xxx&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> do</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  pod </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;AFNetworking&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;2.5.1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>上面内容的意思是，specs 文件由 CocoaPods 提供，项目需要使用支持 ios7.0 及以上的依赖库，并且为指定 target 配置了 2.5.1 版本的 AFNetworking，并忽略依赖库中的所有警告。依赖库的版本号建议明确指定，这样可以避免更新依赖库后对现有工程造成影响，而且可以保证团队所有开发人员使用的版本一致。</p><p>根据 Podfile 文件内容下载安装依赖库</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod install</span></span></code></pre></div><p>执行完成后 CocoaPods 会自动为项目工程设置好相应的系统依赖和编译参数，当依赖库安装完成后，打开项目根目录，会发现多了以下文件及文件夹</p><ul><li>&quot;.xcworkspace&quot;，以后必须通过此 workspace 打开项目。</li><li>&quot;Pods&quot;，CocoaPods 将 Profile 中配置的所有依赖库都下载到这里，并且将所有依赖库打包成单独的静态库供主项目使用。</li><li>&quot;Podfile.lock&quot;，用于保存已经安装的依赖库版本信息。如果在配置依赖库时没有明确指定版本，那么必须将此文件加入到版本控制中，否则有可能造成团队开发中不同成员使用的依赖库版本不一致。</li></ul><p>查看所下载的依赖库是否有新版本</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod outdated</span></span></code></pre></div><p>更新本地 podspec 仓库并更新依赖库</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod update</span></span></code></pre></div><p>更新依赖库且不更新本地 podspec 仓库（速度会快很多）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod update --no-repo-update</span></span></code></pre></div><p>将 CocoaPods 从项目中移除，并还原其对 Xcode 的配置修改（1.0 版本开始支持，以前需要用第三方提供的方式）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod deintegrate</span></span></code></pre></div><h1 id="让自己的开源项目支持-cocoapods" tabindex="-1">让自己的开源项目支持 CocoaPods <a class="header-anchor" href="#让自己的开源项目支持-cocoapods" aria-label="Permalink to &quot;让自己的开源项目支持 CocoaPods&quot;">​</a></h1><p>通过 CocoaPods 创建项目会让整个事情变的简单一些</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod lib create FMDBHelper</span></span></code></pre></div><p>创建完成后项目根目录会包含以下文件及文件夹</p><ul><li>&quot;.travis.yml&quot;，通过 travis-ci 做持续集成要用到的配置文件，一般情况下使用默认配置就可以，如果需要使用持续集成服务，还需要以 GitHub 帐号登录 <a href="https://travis-ci.org" target="_blank" rel="noreferrer">travis-ci</a>，并打开对应项目开关。</li><li>&quot;.gitignore&quot;，建议将 Pods 目录也加入到忽略范围</li><li>&quot;LICENSE&quot;，默认为 MIT</li><li>&quot;FMDBHelper.podspec&quot;，通过 Cocoapods 下载项目时要用到的项目配置文件。</li><li>&quot;README.md&quot;，通过 markdown 语法编写此文件，用于在 GitHub 上显示项目介绍。</li><li>&quot;Pod&quot;，将自己的开源代码和资源文件放到这里</li><li>&quot;Example&quot;，demo 工程，包含测试用的 target。</li></ul><p>在 demo 工程中开发并测试</p><ul><li>将源代码和资源文件分别放到 Pod/Classes 和 Pod/Assets 目录下</li><li>用 pod install 命令为 demo 工程安装依赖库，以后只要新增依赖库的代码或资源文件都需要更新</li><li>开发测试完成后还需要修改 podspec 文件</li></ul><p>在将 podspec 发布到 CocoaPods 的 Git 库之前首先向 CocoaPods 注册你的信息，需要输入邮箱(与 podspec 中写的一致)和名字，稍后还需要验证 email</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod trunk register bj_lijingcheng@163.com &quot;lijingcheng&quot;</span></span></code></pre></div><p>登录 GitHub，release 一版项目并打上标签，标签要与 podspec 中定义的一致，检查并发布 spec 文件，以后需要升级版本时也是用这个命令</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod trunk push FMDBHelper.podspec</span></span></code></pre></div><p>更新本地 spec</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pod repo update</span></span></code></pre></div><h1 id="通过-cocoapods-维护私有库" tabindex="-1">通过 CocoaPods 维护私有库 <a class="header-anchor" href="#通过-cocoapods-维护私有库" aria-label="Permalink to &quot;通过 CocoaPods 维护私有库&quot;">​</a></h1><p>可以按<a href="https://guides.cocoapods.org/making/private-cocoapods.html" target="_blank" rel="noreferrer">官方指导</a>来做，大致步骤与在 GitHub 上维护开源项目相似，区别如下：</p><ul><li><p>需要通过 Git 建立自己的 spec 仓库，并在 Podfile 文件中填加 source</p></li><li><p>通过 pod repo 来查看现有的 spec 仓库</p></li><li><p>通过 pod repo add repo_name source_url 在 ~/.cocoapods/repos/ 目录下新建自己的 spec 仓库</p></li><li><p>通过 pod repo push --allow-warnings repo_name spec_name.podspec 命令将已经写好的 podspec 文件填加到 spec 仓库中</p></li><li><p>私有库新增版本后需要打 tag 并修改 podspec 文件中的 version，然后再次更新 spec 仓库</p></li><li><p>在 Podfile 中可直接通过 pod repo_name 安装私有库</p></li></ul>`,46)])])}const g=a(o,[["render",t]]);export{u as __pageData,g as default};
